  1→import supabase from "./supabase.js";
  2→import { createMediaResponsePayload } from "../utils/mediaVariants.js";
  3→
  4→const NOTIFICATION_LIMIT_MIN = 1;
  5→const NOTIFICATION_LIMIT_MAX = 20;
  6→const NOTIFICATION_DEFAULT_LIMIT = 5;
  7→
  8→const NOTIFICATION_JOURNAL_SELECT = `
  9→    id,
 10→    sender_id,
 11→    receiver_id,
 12→    journal_id,
 13→    repost_journal_id,
 14→    type,
 15→    reaction_type,
 16→    read,
 17→    created_at,
 18→    journals!journal_id(
 19→        title,
 20→        preview_text,
 21→        thumbnail_url,
 22→        created_at,
 23→        users(id, name, image_url, badge)
 24→    ),
 25→    users!sender_id(id, name, image_url, badge)
 26→`;
 27→
 28→const NOTIFICATION_OPINION_SELECT = `
 29→    id,
 30→    sender_id,
 31→    receiver_id,
 32→    opinion_id,
 33→    read,
 34→    created_at,
 35→    opinions!opinion_id(id, opinion, user_id, created_at),
 36→    users!sender_id(id, name, image_url, badge)
 37→`;
 38→
 39→export const parseLimitWithinRange = (value, min = NOTIFICATION_LIMIT_MIN, max = NOTIFICATION_LIMIT_MAX, fallback = NOTIFICATION_DEFAULT_LIMIT) => {
 40→    const parsed = Number.parseInt(value, 10);
 41→    if (Number.isNaN(parsed)) return fallback;
 42→    if (parsed < min || parsed > max) return null;
 43→    return parsed;
 44→};
 45→
 46→const decorateNotificationMedia = (notification) => {
 47→    if (!notification || typeof notification !== 'object') return notification;
 48→
 49→    const senderAvatarMedia = createMediaResponsePayload('avatars', notification.users?.image_url, 'card');
 50→    const journalThumbnailMedia = createMediaResponsePayload('journal-images', notification.journals?.thumbnail_url, 'card');
 51→    const journalUserAvatarMedia = createMediaResponsePayload('avatars', notification.journals?.users?.image_url, 'card');
 52→
 53→    return {
 54→        ...notification,
 55→        users: notification.users ? {
 56→            ...notification.users,
 57→            image_url: senderAvatarMedia?.preferred_url || notification.users.image_url || null,
 58→            avatar_media: senderAvatarMedia
 59→        } : notification.users,
 60→        journals: notification.journals ? {
 61→            ...notification.journals,
 62→            thumbnail_url: journalThumbnailMedia?.preferred_url || notification.journals.thumbnail_url || null,
 63→            thumbnail_media: journalThumbnailMedia,
 64→            users: notification.journals.users ? {
 65→                ...notification.journals.users,
 66→                image_url: journalUserAvatarMedia?.preferred_url || notification.journals.users.image_url || null,
 67→                avatar_media: journalUserAvatarMedia
 68→            } : notification.journals.users
 69→        } : notification.journals
 70→    };
 71→};
