 638→// ── Profile share route: composite OG image for social media ──
 639→app.get('/share/u/:username/image', async (req, res) => {
 640→    const { username } = req.params;
 641→
 642→    // Serve from cache if available
 643→    const cached = getShareImageCached(`profile:${username}`);
 644→    if (cached) {
 645→        res.set('Content-Type', 'image/jpeg');
 646→        res.set('Cache-Control', 'public, max-age=3600');
 647→        return res.send(cached);
 648→    }
 649→
 650→    await ensureShareFonts();
 651→
 652→    try {
 653→        const result = await getUserByUsernameService(username);
 654→        const user = result?.userData?.[0];
 655→        if (!user) {
 656→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 657→        }
 658→
 659→        const displayName = normalizeWhitespace(user.name) || username;
 660→        const handle = `@${normalizeWhitespace(user.username || username)}`;
 661→        const bio = toPreviewText(user.bio || '', 120);
 662→
 663→        // ── Fetch background image ──
 664→        let bgBuffer = null;
 665→        const bgStyle = user.background || {};
 666→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
 667→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
 668→            : null;
 669→        const bgImageUrl = bgImageMatch?.[1];
 670→
 671→        if (bgImageUrl) {
 672→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
 673→            if (bgEval.ok && bgEval.resolvedUrl) {
 674→                try {
 675→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
 676→                    bgBuffer = remote.buffer;
 677→                } catch { /* use fallback gradient */ }
 678→            }
 679→        }
 680→
 681→        // ── Base layer: background or dark gradient ──
 682→        let baseLayer;
 683→        if (bgBuffer) {
 684→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
 685→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
 686→                .toBuffer();
 687→        } else {
 688→            // Use profile's solid background color if available, otherwise dark fallback
 689→            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
 690→                ? bgStyle.background.trim()
 691→                : null;
 692→            const gradientSvg = solidColor
 693→                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 694→                    <rect width="100%" height="100%" fill="${solidColor}"/>
 695→                </svg>`
 696→                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 697→                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
 698→                        <stop offset="0%" stop-color="#1a1a2e"/>
 699→                        <stop offset="100%" stop-color="#16213e"/>
 700→                    </linearGradient></defs>
 701→                    <rect width="100%" height="100%" fill="url(#g)"/>
 702→                </svg>`;
 703→            baseLayer = await sharp(Buffer.from(gradientSvg))
 704→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
 705→                .png()
 706→                .toBuffer();
 707→        }
 708→
 709→        // ── Dark overlay for text readability ──
 710→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 711→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 712→        </svg>`;
 713→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
 714→
 715→        // ── Circular avatar ──
 716→        let avatarComposite = null;
 717→        const avatarSize = 180;
 718→        const avatarUrl = user.image_url;
 719→        if (avatarUrl) {
 720→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 721→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 722→                try {
 723→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 724→                    const circleMask = Buffer.from(
 725→                        `<svg width="${avatarSize}" height="${avatarSize}">
 726→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 727→                        </svg>`
 728→                    );
 729→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 730→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 731→                        .png()
 732→                        .toBuffer();
 733→                    const circularAvatar = await sharp(resizedAvatar)
 734→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 735→                        .png()
 736→                        .toBuffer();
 737→                    avatarComposite = circularAvatar;
 738→                } catch { /* skip avatar */ }
 739→            }
 740→        }
 741→
 742→        // ── Compose all layers ──
 743→        const composites = [
 744→            { input: overlayBuffer, top: 0, left: 0 },
 745→        ];
 746→
 747→        if (avatarComposite) {
 748→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 749→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 750→        }
 751→
 752→        const finalImage = await sharp(baseLayer)
 753→            .composite(composites)
 754→            .jpeg({ quality: 82, mozjpeg: true })
 755→            .toBuffer();
 756→
 757→        setShareImageCached(`profile:${username}`, finalImage);
 758→        res.set('Content-Type', 'image/jpeg');
 759→        res.set('Cache-Control', 'public, max-age=3600');
 760→        return res.send(finalImage);
 761→    } catch (err) {
 762→        console.error('profile share image route error:', err?.message || err);
 763→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 764→    }
 765→});
