 829→app.get('/share/post/:journalId/image', async (req, res) => {
 830→    const { journalId } = req.params;
 831→    const debugMode = isShareImageDebugRequest(req);
 832→
 833→    // Serve from cache if available (skip for debug)
 834→    if (!debugMode) {
 835→        const cached = getShareImageCached(`post:${journalId}`);
 836→        if (cached) {
 837→            res.set('Content-Type', 'image/jpeg');
 838→            res.set('Cache-Control', 'public, max-age=3600');
 839→            return res.send(cached);
 840→        }
 841→    }
 842→
 843→    await ensureShareFonts();
 844→    const debugPayload = {
 845→        ok: false,
 846→        fallback: false,
 847→        journalId,
 848→        stage: 'start',
 849→        reason: '',
 850→        meta: {
 851→            imageCandidateSource: null,
 852→            imageCandidateRaw: null,
 853→            imageCandidateResolved: null,
 854→            upstreamFinalUrl: null,
 855→            upstreamContentType: null,
 856→            upstreamBytes: null,
 857→            outputBytes: null,
 858→        },
 859→    };
 860→
 861→    const fallbackWithReason = (reason) => {
 862→        debugPayload.ok = false;
 863→        debugPayload.fallback = true;
 864→        debugPayload.stage = 'fallback';
 865→        debugPayload.reason = reason;
 866→        if (debugMode) {
 867→            return sendShareImageDebug(res, debugPayload);
 868→        }
 869→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 870→    };
 871→
 872→    try {
 873→        const journal = await getShareJournal(journalId);
 874→        debugPayload.stage = 'journal_loaded';
 875→        if (!journal) {
 876→            return fallbackWithReason('journal_not_found');
 877→        }
 878→
 879→        const shareMeta = buildShareMetaFromJournal(journal);
 880→        debugPayload.stage = 'candidate_extracted';
 881→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
 882→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
 883→
 884→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
 885→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
 886→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
 887→            return fallbackWithReason(candidateEvaluation.reason);
 888→        }
 889→
 890→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
 891→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
 892→            return fallbackWithReason('candidate_is_default_fallback');
 893→        }
 894→
 895→        debugPayload.stage = 'fetching_upstream';
 896→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
 897→        debugPayload.stage = 'upstream_loaded';
 898→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
 899→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
 900→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
 901→
 902→        debugPayload.stage = 'converting_image';
 903→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
 904→        debugPayload.stage = 'converted_image';
 905→        debugPayload.ok = true;
 906→        debugPayload.reason = 'ok';
 907→        debugPayload.meta.outputBytes = ogImageBuffer.length;
 908→
 909→        if (debugMode) {
 910→            return sendShareImageDebug(res, debugPayload);
 911→        }
 912→
 913→        setShareImageCached(`post:${journalId}`, ogImageBuffer);
 914→        res.set('Content-Type', 'image/jpeg');
 915→        res.set('Cache-Control', 'public, max-age=3600');
 916→        return res.send(ogImageBuffer);
 917→    } catch (err) {
 918→        debugPayload.stage = 'error';
 919→        debugPayload.reason = err?.message || 'unknown_error';
 920→        console.error('share image route error:', err?.message || err);
 921→        return fallbackWithReason(debugPayload.reason);
 922→    }
 923→});
