1009→const isMetricsAuthorized = (req) => {
1010→    if (!METRICS_TOKEN) {
1011→        return true;
1012→    }
1013→
1014→    const providedToken = String(req.headers['x-metrics-token'] || '').trim();
1015→    return Boolean(providedToken && providedToken === METRICS_TOKEN);
