1018→const buildMetricsPayload = () => {
1019→    const routeStats = Array.from(metricsState.routeStats.entries())
1020→        .map(([route, stat]) => ({
1021→            route,
1022→            count: stat.count,
1023→            avgDurationMs: stat.count > 0 ? Number((stat.totalDurationMs / stat.count).toFixed(2)) : 0,
1024→            maxDurationMs: Number(stat.maxDurationMs.toFixed(2)),
1025→            bytesSent: stat.bytesSent,
1026→            statusBuckets: stat.statusBuckets,
1027→        }))
1028→        .sort((a, b) => b.count - a.count);
1029→
1030→    return {
1031→        startedAt: metricsState.startedAt,
1032→        requests: metricsState.requests,
1033→        responses: metricsState.responses,
1034→        inFlight: metricsState.inFlight,
1035→        bytesSent: metricsState.bytesSent,
1036→        statusBuckets: metricsState.statusBuckets,
1037→        routeStats: routeStats,
1038→    };
1039→};
